#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    bool placeQueens(int n);
};
bool Solution::placeQueens(int n) {
    vector<vector<bool>> board(n, vector<bool>(n, false));
    return backtrack(board, 0);
}
bool Solution::backtrack(vector<vector<bool>>& board, int row) {
    if (row == n) {
        return true;
    } else {
        for (int col = 0; col < n; ++col) {
            if (!board[row][col] && isValid(board, row, col)) {
                board[row][col] = true;
                if (backtrack(board, row + 1)) {
                    return true;
                }
                board[row][col] = false;
            }
        }
        return false;
    }
}
bool Solution::isValid(vector<vector<bool>>& board, int row, int col) {
    for (int i = 0; i < row; ++i) {
        if (board[i][col]) {
            return false;
        }
    }
    for (int i = 0; i < n; ++i) {
        if (board[row][i]) {
            return false;
        }
    }
    for (int i = 0; i < n; ++i) {
        if (board[i][row - i + i] && !board[i][col - (row - i + i)]) {
            return false;
        }
    }
    for (int i = 0; i < n; ++i) {
        if (board[i][col + row - i] && !board[i][col - (col + row - i)]) {
            return false;
        }
    }
    return true;
}
